'use client';

import React from 'react';

const stats = [
    {
        label: 'Active Patients',
        value: '342',
        subtext: '+12 this week',
        active: true
    },
    {
        label: 'Active Nurses',
        value: '87',
        subtext: '6 on leave',
        active: false
    },
    {
        label: 'Today Bookings',
        value: '28',
        subtext: '4 completed',
        active: false
    },
    {
        label: 'Unassigned Requests',
        value: '7',
        subtext: 'Needs attention',
        active: false,
        alert: true,
        icon: FaExclamationTriangle, // Added icon
        color: 'bg-warning' // Added color
    },
];

const StatsCards = () => {
    return (
        <div className="row g-4 mb-5">
            {stats.map((stat, index) => (
                <div key={stat.label} className="col-12 col-sm-6 col-xl-3">
                    <div className="card border-0 shadow-sm rounded-2xl h-100 transition-300 hover-shadow bg-white">
                        <div className="card-body p-4">
                            <div className="d-flex align-items-center gap-3">
                                <div className={`p-3 rounded-xl d-flex align-items-center justify-content-center ${stat.color.replace('bg-', 'bg-')}`}>
                                    <stat.icon size={22} className={stat.color.replace('bg-', 'text-')} />
                                </div>
                                <div>
                                    <p className="text-secondary small fw-bold mb-1 text-uppercase tracking-wider">{stat.label}</p>
                                    <h3 className="h4 fw-extrabold text-dark mb-0 tracking-tight">{stat.value}</h3>
                                </div>
                            </div>
                            <p className={`small mt-3 fw-semibold ${stat.alert ? 'text-warning' : 'text-muted'}`}>
                                {stat.subtext}
                            </p>
                        </div>
                    </div>
                </div>
            ))}
        </div>
    );
};

export default StatsCards;
